class PriorityQueue:
    def __init__(self):
        self.heap = []

    def enqueue(self, value, priority):
        self.heap.append((priority, value))
        self._sift_up(len(self.heap) - 1)

    def _sift_up(self, index):
        parent = (index - 1) // 2
        if index > 0 and self.heap[parent][0] < self.heap[index][0]:
            self.heap[parent], self.heap[index] = self.heap[index], self.heap[parent]
            self._sift_up(parent)

    def dequeue(self):
        if not self.heap:
            return None
        max_val = self.heap[0][1]
        self.heap[0] = self.heap[-1]
        self.heap.pop()
        if self.heap:
            self._sift_down(0)
        return max_val

    def _sift_down(self, index):
        max_index = index
        left = 2 * index + 1
        right = 2 * index + 2
        if left < len(self.heap) and self.heap[left][0] > self.heap[max_index][0]:
            max_index = left
        if right < len(self.heap) and self.heap[right][0] > self.heap[max_index][0]:
            max_index = right
        if max_index != index:
            self.heap[index], self.heap[max_index] = self.heap[max_index], self.heap[index]
            self._sift_down(max_index)

    def peek(self):
        return self.heap[0][1] if self.heap else None

    def get_queue(self):
        return [(item[1], item[0]) for item in self.heap]

