import java.util.ArrayList;

class PriorityQueue {
    private ArrayList<int[]> heap;

    public PriorityQueue() {
        heap = new ArrayList<>();
    }

    public void enqueue(int value, int priority) {
        heap.add(new int[]{priority, value});
        siftUp(heap.size() - 1);
    }

    private void siftUp(int index) {
        int parent = (index - 1) / 2;
        if (index > 0 && heap.get(parent)[0] < heap.get(index)[0]) {
            int[] temp = heap.get(parent);
            heap.set(parent, heap.get(index));
            heap.set(index, temp);
            siftUp(parent);
        }
    }

    public Integer dequeue() {
        if (heap.isEmpty()) return null;
        int maxVal = heap.get(0)[1];
        heap.set(0, heap.get(heap.size() - 1));
        heap.remove(heap.size() - 1);
        if (!heap.isEmpty()) {
            siftDown(0);
        }
        return maxVal;
    }

    private void siftDown(int index) {
        int maxIndex = index;
        int left = 2 * index + 1;
        int right = 2 * index + 2;
        if (left < heap.size() && heap.get(left)[0] > heap.get(maxIndex)[0]) {
            maxIndex = left;
        }
        if (right < heap.size() && heap.get(right)[0] > heap.get(maxIndex)[0]) {
            maxIndex = right;
        }
        if (maxIndex != index) {
            int[] temp = heap.get(index);
            heap.set(index, heap.get(maxIndex));
            heap.set(maxIndex, temp);
            siftDown(maxIndex);
        }
    }

    public Integer peek() {
        return heap.isEmpty() ? null : heap.get(0)[1];
    }

    public ArrayList<int[]> getQueue() {
        ArrayList<int[]> result = new ArrayList<>();
        for (int[] item : heap) {
            result.add(new int[]{item[1], item[0]});
        }
        return result;
    }
}

class Main {
    public static void main(String[] args) {
        PriorityQueue pq = new PriorityQueue();
        int[][] items = {{10, 2}, {5, 1}, {15, 3}};
        for (int[] item : items) {
            pq.enqueue(item[0], item[1]);
        }
        System.out.println("Queue after enqueue: " + pq.getQueue());
        System.out.println("Peek: " + pq.peek());
        Integer maxVal = pq.dequeue();
        System.out.println("Dequeued: " + maxVal);
        System.out.println("Queue after dequeue: " + pq.getQueue());
    }
}
