#include <stdio.h>
#include <stdlib.h>

#define MAX_SIZE 100

typedef struct PriorityQueue {
    int (*heap)[2];
    int size;
    int capacity;
} PriorityQueue;

PriorityQueue* createPriorityQueue() {
    PriorityQueue* pq = (PriorityQueue*)malloc(sizeof(PriorityQueue));
    pq->heap = (int(*)[2])malloc(MAX_SIZE * sizeof(int[2]));
    pq->size = 0;
    pq->capacity = MAX_SIZE;
    return pq;
}

void siftUp(PriorityQueue* pq, int index) {
    int parent = (index - 1) / 2;
    if (index > 0 && pq->heap[parent][0] < pq->heap[index][0]) {
        int temp[2] = {pq->heap[parent][0], pq->heap[parent][1]};
        pq->heap[parent][0] = pq->heap[index][0];
        pq->heap[parent][1] = pq->heap[index][1];
        pq->heap[index][0] = temp[0];
        pq->heap[index][1] = temp[1];
        siftUp(pq, parent);
    }
}

void enqueue(PriorityQueue* pq, int value, int priority) {
    if (pq->size < pq->capacity) {
        pq->heap[pq->size][0] = priority;
        pq->heap[pq->size][1] = value;
        siftUp(pq, pq->size);
        pq->size++;
    }
}

void siftDown(PriorityQueue* pq, int index) {
    int maxIndex = index;
    int left = 2 * index + 1;
    int right = 2 * index + 2;
    if (left < pq->size && pq->heap[left][0] > pq->heap[maxIndex][0]) {
        maxIndex = left;
    }
    if (right < pq->size && pq->heap[right][0] > pq->heap[maxIndex][0]) {
        maxIndex = right;
    }
    if (maxIndex != index) {
        int temp[2] = {pq->heap[index][0], pq->heap[index][1]};
        pq->heap[index][0] = pq->heap[maxIndex][0];
        pq->heap[index][1] = pq->heap[maxIndex][1];
        pq->heap[maxIndex][0] = temp[0];
        pq->heap[maxIndex][1] = temp[1];
        siftDown(pq, maxIndex);
    }
}

int dequeue(PriorityQueue* pq) {
    if (pq->size == 0) return -1;
    int maxVal = pq->heap[0][1];
    pq->heap[0][0] = pq->heap[pq->size - 1][0];
    pq->heap[0][1] = pq->heap[pq->size - 1][1];
    pq->size--;
    if (pq->size > 0) {
        siftDown(pq, 0);
    }
    return maxVal;
}

int peek(PriorityQueue* pq) {
    return pq->size > 0 ? pq->heap[0][1] : -1;
}

void printQueue(PriorityQueue* pq) {
    printf("[");
    for (int i = 0; i < pq->size; i++) {
        printf("[%d, %d]", pq->heap[i][1], pq->heap[i][0]);
        if (i < pq->size - 1) printf(", ");
    }
    printf("]\n");
}

int main() {
    PriorityQueue* pq = createPriorityQueue();
    int items[][2] = {{10, 2}, {5, 1}, {15, 3}};
    for (int i = 0; i < 3; i++) {
        enqueue(pq, items[i][0], items[i][1]);
    }
    printf("Queue after enqueue: ");
    printQueue(pq);
    printf("Peek: %d\n", peek(pq));
    int maxVal = dequeue(pq);
    printf("Dequeued: %d\n", maxVal);
    printf("Queue after dequeue: ");
    printQueue(pq);
    free(pq->heap);
    free(pq);
    return 0;
}
