        pq.enqueue(item.first, item.second);
    }
    std::cout << "Queue after enqueue: [";
    auto result = pq.getQueue();
    for (size_t i = 0; i < result.size(); i++) {
        std::cout << "[" << result[i].first << ", " << result[i].second << "]";
        if (i < result.size() - 1) std::cout << ", ";
