    pq->heap[0][0] = pq->heap[pq->size - 1][0];
    pq->heap[0][1] = pq->heap[pq->size - 1][1];
    pq->size--;
    if (pq->size > 0) {
        siftDown(pq, 0);
    }
    return maxVal;
}

int peek(PriorityQueue* pq) {
    return pq->size > 0 ? pq->heap[0][1] : -1;
}

void printQueue(PriorityQueue* pq) {
    printf("[");
    for (int i = 0; i < pq->size; i++) {
        printf("[%d, %d]", pq->heap[i][1], pq->heap[i][0]);
        if (i < pq->size - 1) printf(", ");
    }
    printf("]\n");
}

int main() {
