class PriorityQueue {
    private List<int[]> heap;

    public PriorityQueue() {
        heap = new List<int[]>();
    }

    public void Enqueue(int value, int priority) {
        heap.Add(new int[] { priority, value });
        SiftUp(heap.Count - 1);
    }

    private void SiftUp(int index) {
        int parent = (index - 1) / 2;
        if (index > 0 && heap[parent][0] < heap[index][0]) {
            int[] temp = heap[parent];
            heap[parent] = heap[index];
            heap[index] = temp;
            SiftUp(parent);
        }
    }

    public int? Dequeue() {
        if (heap.Count == 0) return null;
        int maxVal = heap[0][1];
        heap[0] = heap[heap.Count - 1];
        heap.RemoveAt(heap.Count - 1);
        if (heap.Count > 0) {
            SiftDown(0);
        }
        return maxVal;
    }

    private void SiftDown(int index) {
        int maxIndex = index;
        int left = 2 * index + 1;
        int right = 2 * index + 2;
        if (left < heap.Count && heap[left][0] > heap[maxIndex][0]) {
            maxIndex = left;
        }
        if (right < heap.Count && heap[right][0] > heap[maxIndex][0]) {
            maxIndex = right;
        }
        if (maxIndex != index) {
            int[] temp = heap[index];
            heap[index] = heap[maxIndex];
            heap[maxIndex] = temp;
            SiftDown(maxIndex);
        }
    }

