class PriorityQueue {
private:
    std::vector<std::pair<int, int>> heap;

    void siftUp(int index) {
        int parent = (index - 1) / 2;
        if (index > 0 && heap[parent].first < heap[index].first) {
            std::swap(heap[parent], heap[index]);
            siftUp(parent);
        }
    }

    void siftDown(int index) {
        int maxIndex = index;
        int left = 2 * index + 1;
        int right = 2 * index + 2;
        if (left < heap.size() && heap[left].first > heap[maxIndex].first) {
            maxIndex = left;
        }
        if (right < heap.size() && heap[right].first > heap[maxIndex].first) {
            maxIndex = right;
        }
        if (maxIndex != index) {
            std::swap(heap[index], heap[maxIndex]);
            siftDown(maxIndex);
        }
    }

public:
    PriorityQueue() {}

    void enqueue(int value, int priority) {
        heap.push_back({priority, value});
        siftUp(heap.size() - 1);
    }

    int dequeue() {
        if (heap.empty()) return -1;
        int maxVal = heap[0].second;
        heap[0] = heap.back();
        heap.pop_back();
        if (!heap.empty()) {
            siftDown(0);
        }
        return maxVal;
    }

