        return heap.empty() ? -1 : heap[0].second;
    }

    std::vector<std::pair<int, int>> getQueue() {
        std::vector<std::pair<int, int>> result;
        for (auto& item : heap) {
            result.push_back({item.second, item.first});
        }
        return result;
    }
};

